--
-- Table structure for table `mt_molduras`
--

DROP TABLE IF EXISTS `mt_molduras`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mt_molduras` (
  `id` int NOT NULL AUTO_INCREMENT,
  `codigo_principal` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `codigos_alternativos` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  `descricao` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  `tipo_moldura` enum('Caixa','Chanfrada','Canaleta','Reta','Clássica') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT 'Reta',
  `tipo_material` enum('Engessada','Envelopada','Laminada','Madeira','Metal','Poliestireno') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT 'Engessada',
  `textura` enum('Lisa','Metálica','Natural','Pintada','Ranhura','Rústica','Tecido','Trabalhada') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT 'Lisa',
  `cor` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `largura_mm` decimal(5,2) DEFAULT NULL COMMENT 'Largura frontal da moldura. Também usada como perda (chanfro)',
  `profundidade_mm` decimal(5,2) DEFAULT NULL,
  `rebaixo_mm` decimal(5,2) DEFAULT NULL,
  `uso_foto` tinyint(1) DEFAULT '0',
  `uso_superficie` tinyint(1) DEFAULT '1',
  `uso_flutuante` tinyint(1) DEFAULT '0',
  `uso_profundidade` tinyint(1) DEFAULT '0',
  `uso_camisa_objeto` tinyint(1) DEFAULT '0',
  `uso_tela` tinyint(1) DEFAULT '0',
  `uso_entre_vidros` tinyint(1) DEFAULT '0',
  `exige_baguete` tinyint(1) DEFAULT '0',
  `uso_tipo` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT 'N = Normal (reta/chanfrada/etc.); C = Caixa (profunda); A = Alumínio',
  `preco_metro` decimal(10,2) DEFAULT NULL,
  `imagem_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `ativo` tinyint(1) DEFAULT '1',
  `criado_em` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ux_mt_molduras_codigo_principal` (`codigo_principal`),
  KEY `idx_mold_superficie` (`ativo`,`uso_superficie`,`uso_tipo`),
  KEY `idx_mold_entrevidros` (`ativo`,`uso_entre_vidros`,`uso_tipo`),
  KEY `idx_mold_profundidade` (`ativo`,`uso_profundidade`,`uso_tipo`),
  KEY `idx_mold_flutuante` (`ativo`,`uso_flutuante`,`uso_tipo`),
  KEY `idx_mold_camisaobj` (`ativo`,`uso_camisa_objeto`,`uso_tipo`),
  KEY `idx_mold_tela` (`ativo`,`uso_tela`,`uso_tipo`),
  KEY `idx_mold_foto` (`ativo`,`uso_foto`,`uso_tipo`)
) ENGINE=InnoDB AUTO_INCREMENT=112 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

